CREATE TABLE ais_vessels (
  mmsi TEXT PRIMARY KEY,
  name TEXT,
  vessel_type TEXT,
  last_position GEOMETRY(Point, 4326),
  last_timestamp TIMESTAMP,
  speed FLOAT,
  course FLOAT
);
CREATE INDEX idx_ais_geom ON ais_vessels USING GIST (last_position);

CREATE TABLE hull_defects (
  time TIMESTAMPTZ,
  vessel_id TEXT,
  defect_type TEXT,
  area_m2 FLOAT,
  geom GEOMETRY(Point, 4326)
);
